69	function BaseButton({
70	  label,
71	  onPress,
72	  disabled = false,
73	  loading = false,
74	  variant,
75	  style,
76	  accessibilityLabel,
77	  testID,
78	}: ButtonProps & { variant: Variant }) {
79	  const interactive = !disabled && !loading;
80	  const { animatedStyle, handlePressIn, handlePressOut } = useBaseButton(interactive);
81	
82	  const variantStyle = variant === 'primary' ? styles.primary : styles.secondary;
83	  const labelColor = disabled ? colors.ink40 : colors.ink;
84	
85	  return (
86	    <Pressable
87	      onPress={interactive ? onPress : undefined}
88	      onPressIn={handlePressIn}
89	      onPressOut={handlePressOut}
90	      disabled={!interactive}
91	      accessibilityRole="button"
92	      accessibilityLabel={accessibilityLabel ?? label}
93	      accessibilityState={{ disabled: !interactive, busy: loading }}
94	      testID={testID}
95	    >
96	      <Animated.View
97	        style={[
98	          styles.base,
99	          variantStyle,
100	          disabled ? styles.disabled : shadows.hard,
101	          animatedStyle,
102	          style,
103	        ]}
104	      >
105	        {loading ? (
106	          <ActivityIndicator color={colors.ink} />
107	        ) : (
108	          <Text style={[textStyles.body, { color: labelColor }]}>{label}</Text>
109	        )}
110	      </Animated.View>
111	    </Pressable>
112	  );
113	}
114	
115	export function ButtonPrimary(props: ButtonProps) {
116	  return <BaseButton {...props} variant="primary" />;
117	}
118	
119	export function ButtonSecondary(props: ButtonProps) {
120	  return <BaseButton {...props} variant="secondary" />;
121	}
