1	import { useEffect, useState } from 'react';
2	import { AccessibilityInfo } from 'react-native';
3	
4	// Session-scoped cache of the last-known OS value. React Native has no synchronous
5	// `isReduceMotionEnabled` вҖ” without this cache every hook mount would flash `false`
6	// for the duration of the async query, briefly running full animations on devices
7	// where reduce-motion is on. First mount in the session still pays this cost; every
8	// mount after that reads the cached value synchronously.
9	let cached: boolean | null = null;
10	
11	export function useReducedMotion(): boolean {
12	  const [reduced, setReduced] = useState<boolean>(cached ?? false);
13	
14	  useEffect(() => {
15	    let mounted = true;
16	    AccessibilityInfo.isReduceMotionEnabled()
17	      .then((enabled) => {
18	        cached = enabled;
19	        if (mounted) setReduced(enabled);
20	      })
21	      .catch(() => {
22	        if (mounted) setReduced(false);
23	      });
24	
25	    const sub = AccessibilityInfo.addEventListener('reduceMotionChanged', (enabled) => {
26	      cached = enabled;
27	      if (mounted) setReduced(enabled);
28	    });
29	    return () => {
30	      mounted = false;
31	      sub.remove();
32	    };
33	  }, []);
34	
35	  return reduced;
36	}
